/**
 * === RED PHASE CROSS-WP JOURNEY TESTS — Keyboard Switching ===
 *
 * Feature: keyboard-switching. Generated by: e2e-test-writer (mode=write — all tests use
 * test.fixme()).
 *
 * Scope: cross-WP journeys spanning UI-PKG-003 (menu command `platform.openKeyboardSelection` +
 * `keyboardSelectionWebViewProvider` — entry path, per-tab projectId resolution, post-close focus
 * return) AND UI-PKG-002 (keyboard-selection web view wiring — render shapes, dropdown data,
 * OK/Cancel persistence semantics). Every journey here exercises BOTH work packages in a single
 * flow; single-WP behavior is pinned by the per-WP functional suites
 * (keyboard-switching-functional-UI-PKG-002.spec.ts / -003.spec.ts) and is NOT duplicated here —
 * what the journeys add is the COMPOSITION: entry → in-dialog interaction → post-close effects →
 * re-entry, asserted end-to-end in one session.
 *
 * Journey anchors (gm-009 + BHV-309 + FN-014):
 *
 * - JRN-1 (gm-009 / TS-018 / TS-016): full OK orchestration — menu → dialog (correct project context)
 *   → select → OK → dialog closes → focus returns to the invoking tab (FN-014 restore-on-close,
 *   DOM-observable slice) → reopen via the same menu → the selection PERSISTED
 *   (ProjectDefaultKeyboards round-trip through the real backend).
 * - JRN-2 / JRN-3 (BHV-309 / TS-017): Cancel journeys — changes made in the dialog are DISCARDED;
 *   reopening shows the pre-Cancel persisted state (including the strong variant where a real
 *   association persisted earlier in the journey survives a Cancel that tried to clear it).
 * - JRN-4 (TS-001 / TS-005 / TS-007 / BHV-602): cross-project context — with two projects open,
 *   invoking from each tab yields a dialog for THAT tab's project, with the render shape derived
 *   from that project's real projectInterfaces (standard shape for zzz6, resource shape for WEB).
 *
 * NOT covered by journey E2E (justified in journey-test-plan.md): the OS-keyboard-activation legs
 * of gm-009 (FocusKeyboardRouter ActivateKeyboard — not DOM-observable; covered by CAP-014/CAP-017
 * backend tests + app-runner runtime verification), error propagation (no setProjectDefaultKeyboard
 * failure can be induced through visible UI against the real backend), cross-app debounce FN-015
 * (requires OS-level alt-tab + keyboard switching outside Playwright's reach), and the
 * missing-keyboard notification chain (precondition not creatable via visible UI).
 *
 * Environment note (Linux CI / WSL — NO IBus): `AvailableKeyboards` enumerates EMPTY here, so
 * journeys that REQUIRE a real keyboard selection carry in-body `test.skip(realKeyboardCount === 0,
 * ...)` guards (the convention established in keyboard-switching-functional-UI-PKG-002.spec.ts).
 * The OK/Cancel/reopen journeys remain fully executable on this host via the SENTINEL selection —
 * with conditional strengthening to a real-keyboard selection on hosts with an OS keyboard layer.
 *
 * Conventions:
 *
 * - Uses `cdp.fixture` only (NEVER papi.fixture or app.fixture).
 * - Navigates via visible UI only (NEVER sendPapiCommand).
 * - Every test has a `// @scenario TS-XXX` comment for traceability.
 * - Journey evidence screenshots land under proofs/component-evidence/journey/.
 * - Helper patterns mirror the sibling per-WP functional suites (frame matcher, project-tab
 *   navigation, dropdown counting) so all three files activate against the same shipped wiring.
 */
import type { FrameLocator, Page } from '@playwright/test';
import { test, expect } from '../../fixtures/cdp.fixture';
import { waitForAppReady } from '../../fixtures/helpers';

const SCREENSHOT_BASE = 'proofs/component-evidence/journey';

/**
 * The keyboard-selection web view's iframe + dock-tab title. The provider pattern in
 * ui-alignment.md registers `title: 'Keyboard'`; BHV-302 may append the project short-name. The
 * tolerant matcher spans both — GREEN-phase reconciliation tightens it to the shipped title.
 */
const KEYBOARD_FRAME = 'iframe[title*="Keyboard" i]';
const KEYBOARD_TAB_REGEX = /Keyboard/i;
/** The "Keyboard..." entry inside the project tab ≡ menu (wired by UI-PKG-003). */
const KEYBOARD_MENU_ITEM_REGEX = /Keyboard/i;

/**
 * Standard-shape fixture (scripture + comments interfaces → both dropdowns). `zzz6` is an editable
 * Paratext 9 test project present in this environment's `~/.platform.bible/projects/Paratext 9
 * Projects/`.
 */
const STANDARD_PROJECT = 'zzz6';

/**
 * Resource-shape fixture (scripture but NO comments interface → single dropdown, "Keyboard:"
 * label). Per the paranext-core PR #2342 factory split, resources do not get the comments
 * projectInterface. GREEN phase reconciles the fixture if its interfaces differ.
 */
const RESOURCE_PROJECT = 'WEB';

/** Sentinel display text (RF-001 resolution: parens REMOVED from PT9's KeyboardSelectionForm_4). */
const SENTINEL_TEXT_REGEX = /Do not switch keyboard/i;

/**
 * Open a project's editor tab from the Home tab's project table. The Home web view
 * (platform-get-resources `home.web-view.tsx`) renders one table row per project with an "Open"
 * button that opens the scripture editor tab for that project.
 */
async function openProjectEditorTab(mainPage: Page, projectShortName: string): Promise<void> {
  // A tab for this project may already be open from an earlier step in the same test.
  const existingTab = mainPage.locator('.dock-tab', { hasText: projectShortName });
  if ((await existingTab.count()) > 0) {
    await existingTab.first().click();
    return;
  }

  // Activate the Home tab, then open the project from its table row.
  await mainPage.locator('.dock-tab', { hasText: 'Home' }).first().click();
  const homeFrame = mainPage.frameLocator('iframe[title*="Home" i]');
  const projectRow = homeFrame.getByRole('row').filter({ hasText: projectShortName }).first();
  await expect(projectRow).toBeVisible({ timeout: 15_000 });
  await projectRow.getByRole('button', { name: /Open/i }).click();

  // The editor tab title carries the project short-name.
  await expect(mainPage.locator('.dock-tab', { hasText: projectShortName }).first()).toBeVisible({
    timeout: 30_000,
  });
}

/**
 * Open the project tab's ≡ menu (the TabToolbar dropdown trigger with accessible name "Project" —
 * `tab-toolbar.component.tsx` passes `tabLabel="Project"`). Only the active tab renders a visible
 * toolbar, so the first visible match is the focused project tab's trigger.
 */
async function openProjectTabMenu(mainPage: Page): Promise<void> {
  await mainPage
    .getByRole('button', { name: 'Project', exact: true })
    .locator('visible=true')
    .first()
    .click();
}

/**
 * Navigate to the keyboard-selection dialog for the given project via visible UI: open the
 * project's editor tab, open its ≡ Project menu, click "Keyboard...". Returns a FrameLocator scoped
 * to the dialog's web-view iframe.
 */
async function openKeyboardDialog(mainPage: Page, projectShortName: string): Promise<FrameLocator> {
  await openProjectEditorTab(mainPage, projectShortName);
  await openProjectTabMenu(mainPage);
  await mainPage.getByRole('menuitem', { name: KEYBOARD_MENU_ITEM_REGEX }).click();
  await expect(mainPage.locator('.dock-tab', { hasText: KEYBOARD_TAB_REGEX })).toBeVisible({
    timeout: 15_000,
  });
  return mainPage.frameLocator(KEYBOARD_FRAME);
}

/**
 * Wait until keyboard enumeration settles (the loading indicator is gone and the text dropdown is
 * interactable). The dialog renders chrome immediately and enumerates async (FN-013).
 */
async function waitForKeyboardsSettled(frame: FrameLocator): Promise<void> {
  await expect(frame.getByTestId('keyboard-selection-text-keyboard')).toBeVisible({
    timeout: 15_000,
  });
  await expect(frame.getByTestId('keyboard-selection-loading')).toHaveCount(0, { timeout: 15_000 });
}

/**
 * Open the text-keyboard dropdown and return the number of REAL (non-sentinel) keyboard options —
 * i.e., the live OS enumeration count. Leaves the dropdown open; callers close it (Escape) or
 * select an item.
 */
async function openTextDropdownAndCountRealKeyboards(frame: FrameLocator): Promise<number> {
  await frame.getByTestId('keyboard-selection-text-keyboard').click();
  await expect(frame.getByTestId('keyboard-selection-sentinel-item')).toBeVisible({
    timeout: 10_000,
  });
  const allOptions = await frame.locator('[role="option"]').count();
  // Each dropdown renders exactly one sentinel item at index 0; the rest are OS keyboards.
  return allOptions - 1;
}

/**
 * Wait until the keyboard dialog's dock tab is gone (the web view closed via
 * `papi.webViews.closeWebView`).
 */
async function expectDialogClosed(mainPage: Page): Promise<void> {
  await expect(mainPage.locator('.dock-tab', { hasText: KEYBOARD_TAB_REGEX })).toHaveCount(0, {
    timeout: 15_000,
  });
}

/**
 * Assert the FN-014 restore-on-close slice that IS DOM-observable: after the dialog closes, the
 * invoking project tab is the active dock tab again (the OS-keyboard activation leg lives in
 * backend tests — see file header).
 */
async function expectFocusReturnedTo(mainPage: Page, projectShortName: string): Promise<void> {
  await expect(mainPage.locator('.dock-tab', { hasText: projectShortName }).first()).toHaveClass(
    /dock-tab-active/,
    { timeout: 10_000 },
  );
}

/**
 * Cleanup helper: with the dialog open and settled, persist the sentinel for the text surface (so
 * the never-configured baseline is restored and journeys are re-runnable in any order).
 */
async function resetTextSelectionToSentinelAndOk(
  mainPage: Page,
  frame: FrameLocator,
): Promise<void> {
  await frame.getByTestId('keyboard-selection-text-keyboard').click();
  await frame.getByTestId('keyboard-selection-sentinel-item').click();
  await frame.getByRole('button', { name: /^OK$/i }).click();
  await expectDialogClosed(mainPage);
}

test.describe('Keyboard Switching Journey Tests (cross-WP: UI-PKG-002 + UI-PKG-003)', () => {
  // Close all tabs except Home to start from a clean state. Platform.Bible persists the dock
  // layout across sessions, so a stale Keyboard dialog or editor tab from a previous test would
  // otherwise pollute these journeys. Each journey opens its own project tab(s).
  test.beforeEach(async ({ mainPage }) => {
    // Escape twice closes any lingering menu dropdown / Radix popover / open Select from a
    // previous test (no-op when nothing is open).
    await mainPage.keyboard.press('Escape');
    await mainPage.keyboard.press('Escape');

    const staleCloseBtn = mainPage
      .locator('.dock-tab')
      .filter({ hasNotText: 'Home' })
      .locator('.dock-tab-close-btn');
    // Bounded cleanup: a real environment never has more than a handful of stale tabs; the cap
    // prevents a runaway loop if the dock close handler regresses.
    const maxClosures = 8;
    for (let i = 0; i < maxClosures; i += 1) {
      // Sequential awaits intentional: count() must complete before deciding to break, and each
      // close re-renders the dock before the next pass.
      // eslint-disable-next-line no-await-in-loop
      const remaining = await staleCloseBtn.count();
      if (remaining === 0) break;
      // Closing a tab re-renders the dock, so each close must complete before the next pass.
      // eslint-disable-next-line no-await-in-loop
      await staleCloseBtn.first().dispatchEvent('click');
      // Brief settle to let React commit the dock-layout state change before re-counting.
      // eslint-disable-next-line no-await-in-loop
      await mainPage.waitForTimeout(300);
    }
  });

  // ═══════════════════════════════════════════════════════════════════════════
  // JRN-1: Happy-path flow — full OK orchestration round trip (gm-009)
  //   entry (UI-PKG-003) → dialog data + selection (UI-PKG-002) → OK write
  //   (UI-PKG-002) → close + focus return (UI-PKG-003 / FN-014) → re-entry
  //   (UI-PKG-003) → persisted selection visible (UI-PKG-002 read wiring)
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-001, TS-016, TS-018 (gm-009 — the UI-observable slice of the full OK
  // orchestration; the ActivateKeyboard leg is backend-verified, see file header)
  test.fixme(
    'should complete the full OK journey: menu → dialog → select → OK → focus returned → reopen shows persisted selection',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // ── Step 1 (UI-PKG-003): entry path — project tab ≡ menu → "Keyboard..." ──
      const frame = await openKeyboardDialog(mainPage, STANDARD_PROJECT);
      await waitForKeyboardsSettled(frame);

      // The dialog carries the invoking tab's project context (webViewId probe → projectId →
      // metadata interpolated into the description — real wired data, not a placeholder).
      await expect(frame.getByTestId('keyboard-selection-description')).toContainText(
        STANDARD_PROJECT,
      );

      // ── Step 2 (UI-PKG-002): make a selection in the text-keyboard dropdown ──
      // Strong variant (hosts with an OS keyboard layer): pick the first REAL keyboard so the
      // persistence round-trip below proves a non-trivial write. Sentinel variant (this no-IBus
      // host): re-affirm the sentinel — the journey chain (entry → OK write loop → close → focus
      // return → re-entry → read wiring) is still exercised end-to-end.
      const realKeyboardCount = await openTextDropdownAndCountRealKeyboards(frame);
      let expectedCollapsedText: string | RegExp = SENTINEL_TEXT_REGEX;
      if (realKeyboardCount > 0) {
        const firstRealOption = frame.locator('[role="option"]').nth(1);
        expectedCollapsedText = (await firstRealOption.innerText()).trim();
        await firstRealOption.click();
      } else {
        await frame.getByTestId('keyboard-selection-sentinel-item').click();
      }
      await expect(frame.getByTestId('keyboard-selection-text-keyboard')).toContainText(
        expectedCollapsedText,
      );

      // JEVD-001: selection made, about to commit.
      await mainPage.screenshot({ path: `${SCREENSHOT_BASE}/JEVD-001-ok-journey-selection.png` });

      // ── Step 3 (UI-PKG-002): OK — per-surface setProjectDefaultKeyboard loop + closeWebView ──
      await frame.getByRole('button', { name: /^OK$/i }).click();
      await expectDialogClosed(mainPage);

      // ── Step 4 (UI-PKG-003 / FN-014): focus returns to the invoking project tab ──
      await expectFocusReturnedTo(mainPage, STANDARD_PROJECT);

      // JEVD-002: post-OK — dialog gone, invoking tab active again.
      await mainPage.screenshot({ path: `${SCREENSHOT_BASE}/JEVD-002-ok-journey-after-ok.png` });

      // ── Step 5 (UI-PKG-003 re-entry + UI-PKG-002 read wiring): reopen → persisted ──
      const frame2 = await openKeyboardDialog(mainPage, STANDARD_PROJECT);
      await waitForKeyboardsSettled(frame2);
      await expect(frame2.getByTestId('keyboard-selection-text-keyboard')).toContainText(
        expectedCollapsedText,
      );

      // JEVD-003: reopened dialog shows the persisted selection (round-trip proof).
      await mainPage.screenshot({ path: `${SCREENSHOT_BASE}/JEVD-003-ok-journey-reopened.png` });

      // Cleanup: restore the never-configured baseline so journeys are order-independent.
      if (realKeyboardCount > 0) {
        await resetTextSelectionToSentinelAndOk(mainPage, frame2);
      } else {
        await frame2.getByRole('button', { name: /Cancel/i }).click();
        await expectDialogClosed(mainPage);
      }
    },
  );

  // ═══════════════════════════════════════════════════════════════════════════
  // JRN-2: Cancel journey — in-dialog changes discarded across close + re-entry
  //   (BHV-309 composed with the UI-PKG-003 entry path and FN-014 focus return)
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-001, TS-017 (BHV-309 — Cancel makes NO writes; the journey adds the cross-WP
  // composition the per-WP suites don't have: entry path, focus return after negative close, and
  // the original state captured at first open re-asserted after a second menu invocation)
  test.fixme(
    'should discard changes on Cancel: change → Cancel → focus returned → reopen shows the original state',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // ── Step 1 (UI-PKG-003): entry path ──
      const frame = await openKeyboardDialog(mainPage, STANDARD_PROJECT);
      await waitForKeyboardsSettled(frame);

      // Capture the ORIGINAL persisted state as the user sees it (collapsed display) — the
      // journey's final assertion is "reopen shows exactly this", independent of whether earlier
      // journeys left a persisted association behind.
      const originalCollapsedText = (
        await frame.getByTestId('keyboard-selection-text-keyboard').innerText()
      ).trim();

      // ── Step 2 (UI-PKG-002): change the selection, then Cancel ──
      // Pick a DIFFERENT option than the original where the enumeration allows it: prefer the
      // first real keyboard whose name differs from the original collapsed display; fall back to
      // the sentinel (still a user interaction on hosts with no OS keyboards).
      const realKeyboardCount = await openTextDropdownAndCountRealKeyboards(frame);
      const optionTexts = await frame.locator('[role="option"]').allInnerTexts();
      const differentRealIndex = optionTexts.findIndex(
        (text, index) => index > 0 && text.trim() !== originalCollapsedText,
      );
      if (realKeyboardCount > 0 && differentRealIndex > 0) {
        await frame.locator('[role="option"]').nth(differentRealIndex).click();
      } else {
        await frame.getByTestId('keyboard-selection-sentinel-item').click();
      }

      // JEVD-004: changed (pending, unsaved) selection just before Cancel.
      await mainPage.screenshot({
        path: `${SCREENSHOT_BASE}/JEVD-004-cancel-journey-pending-change.png`,
      });

      await frame.getByRole('button', { name: /Cancel/i }).click();
      await expectDialogClosed(mainPage);

      // ── Step 3 (UI-PKG-003 / FN-014): focus returns to the invoking tab on negative close ──
      await expectFocusReturnedTo(mainPage, STANDARD_PROJECT);

      // ── Step 4 (UI-PKG-003 re-entry + UI-PKG-002 read wiring): reopen → ORIGINAL state ──
      const frame2 = await openKeyboardDialog(mainPage, STANDARD_PROJECT);
      await waitForKeyboardsSettled(frame2);
      await expect(frame2.getByTestId('keyboard-selection-text-keyboard')).toContainText(
        originalCollapsedText,
      );

      // JEVD-005: reopened dialog shows the pre-Cancel state (no writes happened).
      await mainPage.screenshot({
        path: `${SCREENSHOT_BASE}/JEVD-005-cancel-journey-original-restored.png`,
      });

      await frame2.getByRole('button', { name: /Cancel/i }).click();
      await expectDialogClosed(mainPage);
    },
  );

  // @scenario TS-013, TS-017 (BHV-309 strong variant — a REAL persisted association survives a
  // Cancel that tried to clear it: persist via OK in invocation 1, attempt-to-clear + Cancel in
  // invocation 2, verify survival in invocation 3. Requires a populated OS enumeration.)
  test.fixme(
    'should preserve a persisted keyboard across a cancelled clear attempt (persist → Cancel-discard → still persisted)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // ── Invocation 1 (UI-PKG-003 entry + UI-PKG-002 write): persist a real keyboard ──
      const frame = await openKeyboardDialog(mainPage, STANDARD_PROJECT);
      await waitForKeyboardsSettled(frame);

      const realKeyboardCount = await openTextDropdownAndCountRealKeyboards(frame);
      test.skip(
        realKeyboardCount === 0,
        'Requires ≥1 OS keyboard enumerated (no IBus on this Linux CI/WSL host). The ' +
          'sentinel-only Cancel journey above remains fully executable here; this strong variant ' +
          'runs for real on hosts with an OS keyboard layer.',
      );

      const firstRealOption = frame.locator('[role="option"]').nth(1);
      const persistedName = (await firstRealOption.innerText()).trim();
      await firstRealOption.click();
      await frame.getByRole('button', { name: /^OK$/i }).click();
      await expectDialogClosed(mainPage);

      // ── Invocation 2 (UI-PKG-002 discard semantics): try to clear it, then Cancel ──
      const frame2 = await openKeyboardDialog(mainPage, STANDARD_PROJECT);
      await waitForKeyboardsSettled(frame2);
      await expect(frame2.getByTestId('keyboard-selection-text-keyboard')).toContainText(
        persistedName,
      );
      await frame2.getByTestId('keyboard-selection-text-keyboard').click();
      await frame2.getByTestId('keyboard-selection-sentinel-item').click();
      await frame2.getByRole('button', { name: /Cancel/i }).click();
      await expectDialogClosed(mainPage);
      await expectFocusReturnedTo(mainPage, STANDARD_PROJECT);

      // ── Invocation 3 (UI-PKG-003 durable registration + UI-PKG-002 read): survived ──
      const frame3 = await openKeyboardDialog(mainPage, STANDARD_PROJECT);
      await waitForKeyboardsSettled(frame3);
      await expect(frame3.getByTestId('keyboard-selection-text-keyboard')).toContainText(
        persistedName,
      );

      // JEVD-006: the persisted association survived the cancelled clear attempt.
      await mainPage.screenshot({
        path: `${SCREENSHOT_BASE}/JEVD-006-cancel-journey-persisted-survives.png`,
      });

      // Cleanup: restore the never-configured baseline.
      await resetTextSelectionToSentinelAndOk(mainPage, frame3);
    },
  );

  // ═══════════════════════════════════════════════════════════════════════════
  // JRN-4: Cross-project context — two projects open, the dialog reflects the
  //   INVOKING tab's project each time (per-tab probe from UI-PKG-003 driving
  //   the projectInterfaces-derived render shape from UI-PKG-002)
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-001, TS-005, TS-007 (BHV-602 single entry point invoked from two different tabs
  // in one session; BHV-303 resource shape vs standard shape derived from each project's REAL
  // projectInterfaces — the cross-WP data flow is: tab menu (WP-003) → projectId probe (WP-003) →
  // metadata → dialog render shape + description (WP-002))
  test.fixme(
    'should show the correct project context and render shape when invoked from each of two open project tabs',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Open BOTH project tabs up front — the resource first so a wrong "first/global project"
      // implementation would leak WEB into the standard-project dialog below (and vice versa on
      // the second leg).
      await openProjectEditorTab(mainPage, RESOURCE_PROJECT);
      await openProjectEditorTab(mainPage, STANDARD_PROJECT);

      // ── Leg 1: invoke from the STANDARD project tab ──
      await openProjectTabMenu(mainPage);
      await mainPage.getByRole('menuitem', { name: KEYBOARD_MENU_ITEM_REGEX }).click();
      await expect(mainPage.locator('.dock-tab', { hasText: KEYBOARD_TAB_REGEX })).toBeVisible({
        timeout: 15_000,
      });
      const standardFrame = mainPage.frameLocator(KEYBOARD_FRAME);
      await waitForKeyboardsSettled(standardFrame);

      // Correct project context: the description names zzz6, NOT the other open project.
      const standardDescription = standardFrame.getByTestId('keyboard-selection-description');
      await expect(standardDescription).toContainText(STANDARD_PROJECT);
      await expect(standardDescription).not.toContainText(RESOURCE_PROJECT);

      // Standard render shape (zzz6 has scripture + comments interfaces): both dropdowns.
      await expect(standardFrame.getByTestId('keyboard-selection-notes-keyboard')).toBeVisible();
      await expect(standardFrame.getByTestId('keyboard-selection-text-label')).toHaveText(
        /Keyboard for text:/i,
      );

      // JEVD-007: standard-project dialog from the zzz6 tab (with WEB also open).
      await mainPage.screenshot({
        path: `${SCREENSHOT_BASE}/JEVD-007-cross-project-standard-context.png`,
      });

      await standardFrame.getByRole('button', { name: /Cancel/i }).click();
      await expectDialogClosed(mainPage);

      // ── Leg 2: invoke from the RESOURCE project tab in the SAME session ──
      await openProjectEditorTab(mainPage, RESOURCE_PROJECT);
      await openProjectTabMenu(mainPage);
      await mainPage.getByRole('menuitem', { name: KEYBOARD_MENU_ITEM_REGEX }).click();
      await expect(mainPage.locator('.dock-tab', { hasText: KEYBOARD_TAB_REGEX })).toBeVisible({
        timeout: 15_000,
      });
      const resourceFrame = mainPage.frameLocator(KEYBOARD_FRAME);
      await waitForKeyboardsSettled(resourceFrame);

      // Correct project context flipped: the description names WEB, NOT zzz6 (proves the probe
      // resolves the INVOKING tab each time — not a cached/global project).
      const resourceDescription = resourceFrame.getByTestId('keyboard-selection-description');
      await expect(resourceDescription).toContainText(RESOURCE_PROJECT);
      await expect(resourceDescription).not.toContainText(STANDARD_PROJECT);

      // Resource render shape (WEB has scripture but NO comments interface): notes controls
      // omitted entirely; the text label simplifies to "Keyboard:".
      await expect(resourceFrame.getByTestId('keyboard-selection-notes-keyboard')).toHaveCount(0);
      await expect(resourceFrame.getByTestId('keyboard-selection-notes-label')).toHaveCount(0);
      await expect(resourceFrame.getByTestId('keyboard-selection-text-label')).toHaveText(
        /^Keyboard:$/i,
      );

      // JEVD-008: resource dialog from the WEB tab in the same session.
      await mainPage.screenshot({
        path: `${SCREENSHOT_BASE}/JEVD-008-cross-project-resource-context.png`,
      });

      await resourceFrame.getByRole('button', { name: /Cancel/i }).click();
      await expectDialogClosed(mainPage);
    },
  );
});
